# Quarterly backlog review — scoring drift analysis

# Track how opportunity scores change over time as conditions evolve
from dataclasses import dataclass
from datetime import date

@dataclass
class ScoringRecord:
    opportunity_id: str
    review_date: date
    value_score: float
    feasibility_score: float
    tier: str
    score_change_reason: str    # What changed since last review

def detect_promotions(history: list[ScoringRecord]) -> list[str]:
    # Find opportunities that moved from Park/T2 to T1 between reviews
    by_opp: dict = {}
    for r in sorted(history, key=lambda x: x.review_date):
        if r.opportunity_id not in by_opp:
            by_opp[r.opportunity_id] = []
        by_opp[r.opportunity_id].append(r)

    promotions = []
    for opp_id, records in by_opp.items():
        if len(records) >= 2:
            prev, curr = records[-2], records[-1]
            if prev.tier in ('Park', 'T2') and curr.tier == 'T1':
                promotions.append(
                    f'{opp_id}: {prev.tier} -> T1 on {curr.review_date} '
                    f'({curr.score_change_reason})'
                )
    return promotions
